import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as n,c as t,f as r,a as e,b as o,d,e as i}from"./app-48b5f0c8.js";const s={},p=e("blockquote",null,[e("p",null,[o("如何从 "),e("code",null,"X11"),o(" 转向 "),e("code",null,"Wayland"),o(" (Manjaro 专场)")])],-1),h=e("h1",{id:"intro",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#intro","aria-hidden":"true"},"#"),o(" Intro")],-1),g=e("code",null,"KDE",-1),u=e("code",null,"GNOME",-1),_=e("code",null,"X11",-1),m=e("code",null,"Wayland",-1),f={href:"https://www.zhihu.com/question/503270852",target:"_blank",rel:"noopener noreferrer"},y=i('<p>关于为什么突然想从 <code>X11</code> 转向 <code>Wayland</code>，这个过程较为曲折，概括来说就是，想使用一个渲染更快，架构更新，并且是平铺式的桌面</p><p>在网上也看了许多配置完成的例子，比如 <code>dwm</code>，<code>i3wm</code> 等等平铺式窗口管理器，但最后选择的是 <code>wayland</code> 协议下的 <code>hyprland</code> 窗口管理器，然后用一些插件来完善桌面</p><div class="hint-container tip"><p class="hint-container-title">提示</p><p>当然本质上还是在玩赛博暖暖</p></div><p>下面是我的成果<br><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202402230022942.png" alt="image.png" loading="lazy"></p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202402230023153.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p><code>Hyprland</code> 的动画效果做的太过丝滑，配上一些手势控制后，可以达到 <code>Mac</code> 一样的效果，这是我在 <code>KDE</code> 下从没做到过的（因为那个手势控制的软件不够灵敏）</p><p>并且，使用平铺桌面之后，甚至可以直接抛弃鼠标了（<code>vim</code> 党大胜利），虽然写代码还没有完全转向 <code>neovim</code>，但在不用鼠标这一点上已经相去不远了。</p><div class="hint-container danger"><p class="hint-container-title">警告</p><p>注意，<code>wayland</code> 还不够成熟，许多软件在 <code>wayland</code> 协议下没法工作，比如 <code>electron</code> 这种框架的，就必须运行在 <code>xwayland</code> 转化协议下才能够工作</p></div><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h1><h2 id="一些偷懒方法" tabindex="-1"><a class="header-anchor" href="#一些偷懒方法" aria-hidden="true">#</a> 一些偷懒方法</h2><p>这里推荐一个脚本，可以快速完成配置，然后进行一些微调，对于不想折腾的来说这是个不错的选择</p>',11),b={href:"https://gitlab.com/stephan-raabe/dotfiles",target:"_blank",rel:"noopener noreferrer"},w={href:"https://hyprland.org/hall_of_fame/",target:"_blank",rel:"noopener noreferrer"},k=e("li",null,[o("其他人的一些参考 "),e("code",null,"dotfiles")],-1),v=e("h2",{id:"我的配置",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#我的配置","aria-hidden":"true"},"#"),o(" 我的配置")],-1),x={href:"https://wiki.hyprland.org/",target:"_blank",rel:"noopener noreferrer"},q={href:"https://github.com/topdeoo/hyprland-dotfiles",target:"_blank",rel:"noopener noreferrer"},M=i('<ul><li>应用程序启动器：<code>rofi</code> ，主题是网上搜刮找到的</li><li>顶部导航栏：<code>waybar</code>，主题搜刮来的，但也自己写了一些配置，但注意的是 <code>waybar</code> 其实和其他功能联动不强，你也可以使用 <code>ewww</code> 这个软件（似乎是 <code>Rust</code> 写的，速度应该有保障）</li><li>终端模拟器：<code>kitty</code>，主题是网上搜刮的，字体本人更喜欢使用 <code>Monaco</code>，你也可以选择自己喜欢的字体，例如 <code>Maple</code>, <code>Menlo</code>（大概是这个名字），但请注意一定要选择 <code>Nerd Font</code>，为了后续的美化。而终端模拟器你也可以选择 <code>Alacritty</code>，虽然是 <code>Rust</code> 写的，但似乎在动画和速度上不如 <code>Kitty</code>，如果你有心思去解决一些 <code>BUG</code> 的话，也可以选择 <code>Wezterm</code>，因为这个模拟器还不支持 <code>Hyprland</code></li><li>文件管理器：<code>Nautilus</code> 对于文件管理器的选择其实有很多，例如 <code>KDE</code> 的 <code>Dolphin</code>，可以选择一个自己喜欢的。当然，我们也可以使用之前 <code>KDE</code> 下的主题，只需要下载 <code>nwg-looking</code> 然后选择之前下载的主题即可。 <ul><li>例如文件夹主题：<img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202402230002634.png" alt="image.png" loading="lazy"></li></ul></li><li>剪切板管理：<code>copyq</code>，如果你对脚本钟爱的话，可以自己写一个脚本然后在 <code>hyprland/hyprland.conf</code> 里面用快捷键执行（我感觉 <code>copyq</code> 比 <code>cliphist</code> 好用很多</li><li>剪切板： <code>wl-clipboard</code>，只有这一个选择</li><li>截图工具：<code>hyprland-interactive-screenshot</code>，并没有和网上大部分一样用脚本来解决，只不过这个需要定时清理以下截屏的文件夹。</li><li>锁屏：<code>swaylock</code>，简单好用</li><li>壁纸： <code>swagbg</code>，神写的壁纸软件（纯静态，如果想要花里胡哨的动态效果，<code>swww</code> 是个不错的选择），你也可以安装 <code>waypaper</code> 来随时更换壁纸而不需要每次都去写配置文件。</li><li>消息通知（弹窗）: <code>mako</code> 简单好用，虽然主题也是白嫖网上的</li><li>终端美化与 <code>shell</code>: <code>starship</code> &amp; <code>fish</code>，原本使用的是 <code>zsh</code>，但在某一天我的 <code>zsh</code> 再也无法自动读取 <code>.zshrc</code> 的内容了，于是就换成了更智能的 <code>fish</code></li><li>录屏相关： <code>obs</code> &amp; <code>pipewire</code> &amp; <code>wireplumbe</code> 这些都在 <code>Wiki</code> 中说过了</li><li>手势软件：<code>fusuma</code>，极品，让我的 <code>Linux</code> 直接拥有 <code>Mac</code> 的触控板体验（略显夸张但真的很好用）</li><li>网络管理： <code>NetworkManager</code>，好用不解释</li><li>输入法：<code>fcitx5</code>，最常用的输入法，请务必选择。</li></ul><p>字体：中文字体强烈推荐 霞鹜文楷，英文字体推荐 <code>Monaco</code> 因为是等宽字体看起来输入很多。</p><h2 id="遇到的问题" tabindex="-1"><a class="header-anchor" href="#遇到的问题" aria-hidden="true">#</a> 遇到的问题</h2><blockquote><p>应该遇到了很多问题，但由于时间跨度太大，导致我写这篇文章的时候已经记不起太多了，后面一定及时补充</p></blockquote><h3 id="picgo-上传问题" tabindex="-1"><a class="header-anchor" href="#picgo-上传问题" aria-hidden="true">#</a> Picgo 上传问题</h3><p>这个问题主要是因为 <code>picgo</code> 的脚本获取剪切板不太对，解决这个问题首先我们需要保证使用的是 <code>picgo</code> 而不是 <code>picgo-core</code>，然后，在下图中选择 “使用内置剪切板上传” 即可解决问题(当然，需要保证使用 <code>copyq</code> 这个管理软件)</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202402230021751.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="连接不上新网络-反复要求输入密码" tabindex="-1"><a class="header-anchor" href="#连接不上新网络-反复要求输入密码" aria-hidden="true">#</a> 连接不上新网络（反复要求输入密码）</h3><p>一般遇到这个问题，可能是因为密钥环缺少管理工具，首先下载一个密钥环管理软件 <code>seahorse</code> 就可以解决。</p><p>如果这样也无法解决的话，那可能只能使用 <code>iwctl</code> 进行 <code>tui</code> 登陆。</p>',10);function N(z,E){const c=l("ExternalLinkIcon");return n(),t("div",null,[p,r("more"),h,e("p",null,[o("关于 "),g,o("，"),u,o("，"),_,o(),m,o(" 的区别和联系请看： "),e("a",f,[o("GNOME，Xorg，X Window，X Server，Wayland是什么关系"),d(c)])]),y,e("ul",null,[e("li",null,[e("a",b,[o("ML4W"),d(c)])]),e("li",null,[e("a",w,[o("名人堂"),d(c)])]),k]),v,e("p",null,[o("在 Hyprland 的 "),e("a",x,[o("Wiki"),d(c)]),o(" 中，官方给出了很多新手提示，并且也给出了一些软件的建议。")]),e("p",null,[o("你可以在 "),e("a",q,[o("hypr-dotfiles"),d(c)]),o(" 找到我的配置，我使用的配置为：")]),M])}const D=a(s,[["render",N],["__file","Hyprland-Yes.html.vue"]]);export{D as default};
